import React from "react";

export const Process = (props) => {
  const d = props.data;
  return (
    <div id="process" className="text-center 55lab-process">
      <div className="container">
        <div className="section-title">
          <h2>{d ? d.title : "…"}</h2>
          {d && d.subtitle ? <p>{d.subtitle}</p> : null}
        </div>
        <div className="row">
          {d && d.steps
            ? d.steps.map((step, i) => (
                <div key={step.title} className="col-xs-12 col-sm-6 col-md-3">
                  <div className="55lab-step">
                    <div className="55lab-step-num">{i + 1}</div>
                    <h3>{step.title}</h3>
                    <p>{step.text}</p>
                  </div>
                </div>
              ))
            : null}
        </div>
      </div>
    </div>
  );
};
